interface Props {
  isPlaying: boolean;
  togglePlay: () => void;
  audioRef: React.RefObject<HTMLAudioElement>;
}

const SectionMusic: React.FC<Props> = ({ isPlaying, togglePlay, audioRef }) => {
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const updateProgress = () => {
      if (audioRef.current) {
        const current = audioRef.current.currentTime;
        const duration = audioRef.current.duration || 100;
        setProgress((current / duration) * 100);
      }
    };

    const interval = setInterval(updateProgress, 1000);
    return () => clearInterval(interval);
  }, [audioRef]);

  return (
    <section className="h-screen w-full relative flex flex-col justify-end pb-12 px-6 overflow-hidden bg-gradient-to-b from-rose-900/40 to-black">
      {/* Background Ambience */}
      <div className="absolute inset-0 -z-10">
         <img 
            src="https://picsum.photos/seed/cover/800/800" 
            alt="Blur BG" 
            className="w-full h-full object-cover opacity-30 blur-3xl scale-125"
         />
      </div>

      <motion.div 
        initial={{ opacity: 0, y: 50 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 1 }}
        className="w-full max-w-md mx-auto"
      >
        {/* Album Art */}
        <div className="w-full aspect-square bg-zinc-800 rounded-lg shadow-2xl mb-8 overflow-hidden relative group">
          <img 
            src="https://picsum.photos/seed/cover/800/800" 
            alt="Album Cover" 
            className={`w-full h-full object-cover transition-transform duration-700 ${isPlaying ? 'scale-105' : 'scale-100'}`} 
          />
          {!isPlaying && (
            <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
                <button onClick={togglePlay} className="bg-green-500 rounded-full p-4 hover:scale-110 transition-transform">
                    <Play fill="black" className="text-black w-8 h-8 ml-1" />
                </button>
            </div>
          )}
        </div>

        {/* Title & Info */}
        <div className="flex justify-between items-end mb-6">
          <div>
            <h1 className="text-2xl font-bold text-white mb-1">Nossa Música Favorita</h1>
            <p className="text-zinc-400 text-sm">A trilha sonora da nossa vida</p>
          </div>
          <Heart className="text-green-500 w-6 h-6 fill-green-500 animate-pulse" />
        </div>

        {/* Progress Bar */}
        <div className="w-full h-1 bg-zinc-600 rounded-full mb-2 overflow-hidden">
          <motion.div 
            className="h-full bg-white rounded-full"
            style={{ width: `${progress}%` }}
          />
        </div>
        <div className="flex justify-between text-xs text-zinc-400 mb-6">
          <span>{isPlaying ? "Tocando..." : "Pausado"}</span>
          <span>∞</span>
        </div>

        {/* Controls */}
        <div className="flex justify-center items-center gap-8 mb-8">
           <Share2 className="text-zinc-400 w-6 h-6" />
           <button 
             onClick={togglePlay}
             className="w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-lg active:scale-95 transition-transform"
           >
             {isPlaying ? (
               <Pause className="text-black w-8 h-8 fill-black" />
             ) : (
               <Play className="text-black w-8 h-8 fill-black ml-1" />
             )}
           </button>
           <div className="w-6" /> {/* Spacer for symmetry */}
        </div>

        <motion.p 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 2, duration: 1 }}
          className="text-center text-rose-200/80 italic text-sm font-serif"
