import React, { useEffect, useState } from 'react';
import { CountdownTime } from '../types';
import { SPECIAL_DATE } from '../constants';
import { motion } from 'framer-motion';

const SectionCounter: React.FC = () => {
  const [timeLeft, setTimeLeft] = useState<CountdownTime>({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [isFuture, setIsFuture] = useState(false);

  useEffect(() => {
    const calculateTime = () => {
      const target = new Date(SPECIAL_DATE).getTime();
      const now = new Date().getTime();

      // Determine if we are counting down to a future date or counting up from a past date
      let diff = target - now;
      let future = true;

      if (diff < 0) {
        diff = now - target;
        future = false;
      }

      setIsFuture(future);

      const days = Math.floor(diff / (1000 * 60 * 60 * 24));
      const hours = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
      const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
      const seconds = Math.floor((diff % (1000 * 60)) / 1000);

      setTimeLeft({ days, hours, minutes, seconds });
    };

    calculateTime();
    const timer = setInterval(calculateTime, 1000);
    return () => clearInterval(timer);
  }, []);

  const TimeUnit = ({ value, label }: { value: number; label: string }) => (
    <div className="flex flex-col items-center mx-2 md:mx-4">
      <motion.div 
        key={value}
        initial={{ y: -5, opacity: 0.5 }}
        animate={{ y: 0, opacity: 1 }}
        className="text-4xl md:text-6xl font-light text-rose-950 font-serif"
      >
        {String(value).padStart(2, '0')}
      </motion.div>
      <span className="text-xs md:text-sm uppercase tracking-widest text-rose-800 mt-2">{label}</span>
    </div>
  );

  // Formatting the date for display
  const dateObj = new Date(SPECIAL_DATE);
  const formattedDate = new Intl.DateTimeFormat('pt-BR', { day: '2-digit', month: 'long', year: 'numeric' }).format(dateObj);

  return (
    <section className="min-h-screen w-full bg-rose-50 flex flex-col items-center justify-center py-20 px-6">
      <motion.div
        initial={{ opacity: 0 }}
        whileInView={{ opacity: 1 }}
        transition={{ duration: 1 }}
        className="text-center max-w-lg"
      >
        <h2 className="text-2xl md:text-3xl font-serif text-rose-900 mb-2">
          {isFuture ? "Esperando por..." : "Desde o dia que mudou tudo..."}
        </h2>
        <p className="text-rose-700/60 mb-12 text-sm">{formattedDate}</p>

        <div className="flex justify-center items-center flex-wrap mb-16">
          <TimeUnit value={timeLeft.days} label="Dias" />
          <span className="text-3xl text-rose-300 font-serif mt-[-2rem]">:</span>
          <TimeUnit value={timeLeft.hours} label="Horas" />
          <span className="text-3xl text-rose-300 font-serif mt-[-2rem]">:</span>
          <TimeUnit value={timeLeft.minutes} label="Min" />
          <span className="text-3xl text-rose-300 font-serif mt-[-2rem]">:</span>
          <TimeUnit value={timeLeft.seconds} label="Seg" />
        </div>

        <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.5 }}
            className="relative p-8 bg-white/50 backdrop-blur-sm rounded-2xl shadow-sm border border-rose-100"
        >
            <p className="text-rose-900 font-serif italic text-lg md:text-xl leading-relaxed">
            “O amor ganhou um novo nome, um novo sentido e um novo coração.”
            </p>
        </motion.div>
      </motion.div>
    </section>
  );
};

export default SectionCounter;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { BOOK_PAGES } from '../constants';
import { ArrowLeft, ArrowRight } from 'lucide-react';

const SectionBook: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);

  // Logic: Show 2 pages at a time on desktop, 1 on mobile
  const isDesktop = typeof window !== 'undefined' && window.innerWidth >= 768;
  const itemsPerPage = isDesktop ? 2 : 1;
  const totalViews = Math.ceil(BOOK_PAGES.length / itemsPerPage);

  const nextPage = () => {
    if (currentIndex < totalViews - 1) {
      setCurrentIndex(curr => curr + 1);
    }
  };

  const prevPage = () => {
    if (currentIndex > 0) {
      setCurrentIndex(curr => curr - 1);
    }
  };

  const currentPages = BOOK_PAGES.slice(
      currentIndex * itemsPerPage, 
      (currentIndex * itemsPerPage) + itemsPerPage
  );

  return (
    <section className="min-h-screen w-full bg-[#fdfbf7] flex flex-col items-center justify-center py-20 px-4 overflow-hidden">
      <div className="text-center mb-10">
        <h2 className="text-3xl font-serif text-amber-900 mb-2">Livro do Amor</h2>
        <p className="text-amber-900/40 text-sm">Nossa história escrita em cada detalhe</p>
      </div>

      <div className="relative w-full max-w-5xl aspect-[3/4] md:aspect-[3/2] flex items-center justify-center">
        {/* Book Container */}
        <div className="relative w-full h-full bg-[#fdfbf7] shadow-2xl rounded-sm border border-amber-900/10 flex overflow-hidden">

            <AnimatePresence mode='wait'>
                <motion.div 
                    key={currentIndex}
                    initial={{ opacity: 0, rotateY: -10, scale: 0.95 }}
                    animate={{ opacity: 1, rotateY: 0, scale: 1 }}
                    exit={{ opacity: 0, rotateY: 10, scale: 0.95 }}
                    transition={{ duration: 0.6, ease: "easeInOut" }}
                    className="w-full h-full flex flex-col md:flex-row bg-[#fffefc]"
                    style={{ perspective: 1000 }}
                >
                    {/* Spine Effect Center (Desktop only) */}
                    <div className="hidden md:block absolute left-1/2 top-0 bottom-0 w-8 bg-gradient-to-r from-black/5 via-transparent to-black/10 z-20 -translate-x-1/2" />

                    {currentPages.map((page, index) => (
                        <div key={page.id} className="flex-1 relative h-full p-8 md:p-16 flex flex-col items-center justify-center border-r border-amber-900/5 last:border-0">
                            {/* Page Texture */}
                            <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cream-paper.png')] opacity-50 pointer-events-none" />

                            {page.content.type === 'image' ? (
                                <div className="relative w-full h-[70%] shadow-md rotate-1 p-2 bg-white border border-gray-100">
                                    <img 
                                        src={page.content.value} 
                                        alt="Book Memory" 
                                        className="w-full h-full object-cover sepia-[.3]" 
                                    />
                                </div>
                            ) : (
                                <div className="prose prose-amber text-center">
                                    <p className="font-serif text-xl md:text-2xl text-amber-950 leading-loose whitespace-pre-wrap">
                                        {page.content.value}
                                    </p>
                                    <div className="w-16 h-px bg-amber-900/30 mx-auto mt-8" />
                                </div>
                            )}

                            {/* Page Number */}
                            <div className="absolute bottom-6 text-xs text-amber-900/40 font-serif">
                                - {page.id} -
                            </div>
                        </div>
                    ))}

                    {/* If only 1 item on desktop (odd number ending), fill empty space */}
                    {isDesktop && currentPages.length === 1 && (
                         <div className="flex-1 h-full bg-[#fffefc]" />
                    )}

                </motion.div>
            </AnimatePresence>

        </div>

        {/* Navigation Controls */}
        <button 
            onClick={prevPage}
            disabled={currentIndex === 0}
            className={`absolute left-2 md:-left-16 p-3 rounded-full bg-white/80 shadow-lg text-amber-900 transition-all ${currentIndex === 0 ? 'opacity-30 cursor-not-allowed' : 'hover:scale-110 opacity-100'}`}
        >
            <ArrowLeft />
        </button>

        <button 
            onClick={nextPage}
            disabled={currentIndex === totalViews - 1}
            className={`absolute right-2 md:-right-16 p-3 rounded-full bg-white/80 shadow-lg text-amber-900 transition-all ${currentIndex === totalViews - 1 ? 'opacity-30 cursor-not-allowed' : 'hover:scale-110 opacity-100'}`}
        >
            <ArrowRight />
        </button>
      </div>

    </section>
  );
};

export default SectionBook;

import React, { useState, useRef, useEffect } from 'react';
import SectionMusic from './components/SectionMusic';
import SectionTour from './components/SectionTour';
import SectionStories from './components/SectionStories';
import SectionCounter from './components/SectionCounter';
import SectionBook from './components/SectionBook';
import { MUSIC_URL } from './constants';
import { Volume2, VolumeX } from 'lucide-react';

function App() {
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement>(null);

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play().catch(e => console.log("User interaction required", e));
      }
      setIsPlaying(!isPlaying);
    }
  };

  // Ensure audio loops and is persistent
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.loop = true;
      audioRef.current.volume = 0.5;
    }
  }, []);

  return (
    <main className="w-full relative bg-black text-white">
      {/* Hidden Global Audio */}
      <audio ref={audioRef} src={MUSIC_URL} />

      {/* Persistent Floating Volume Control (Visible after first section) */}
      <div className="fixed top-6 right-6 z-50 mix-blend-difference">
         <button onClick={togglePlay} className="p-2 rounded-full bg-white/10 backdrop-blur-md hover:bg-white/20 transition-colors">
            {isPlaying ? <Volume2 className="text-white w-5 h-5" /> : <VolumeX className="text-white w-5 h-5" />}
         </button>
      </div>

      {/* Sections */}
      <div className="snap-y snap-mandatory h-screen overflow-y-scroll scroll-smooth no-scrollbar">

          <div className="snap-start h-screen w-full">
            <SectionMusic isPlaying={isPlaying} togglePlay={togglePlay} audioRef={audioRef} />
          </div>

          <div className="snap-start min-h-screen w-full">
            <SectionTour />
          </div>

          <div className="snap-start min-h-screen w-full">
            <SectionStories />
          </div>

          <div className="snap-start min-h-screen w-full">
            <SectionCounter />
          </div>

          <div className="snap-start min-h-screen w-full">
            <SectionBook />
          </div>

          {/* Footer */}
          <div className="snap-end bg-[#fdfbf7] py-8 text-center text-amber-900/30 text-xs">
            <p>Feito com amor ❤️</p>
          </div>
      </div>
    </main>
  );
}

export default App;

