const SectionBook: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [direction, setDirection] = useState(0); // -1 for left, 1 for right
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Logic: Show 2 pages at a time on desktop, 1 on mobile
  const isDesktop = typeof window !== 'undefined' && window.innerWidth >= 768;
  const itemsPerPage = isDesktop ? 2 : 1;
  const totalViews = Math.ceil(BOOK_PAGES.length / itemsPerPage);

  // Initialize audio
  useEffect(() => {
    audioRef.current = new Audio(PAGE_FLIP_AUDIO);
    audioRef.current.volume = 0.4; // Subtle volume
  }, []);

  const playSound = () => {
    if (audioRef.current) {
      audioRef.current.currentTime = 0;
      audioRef.current.play().catch(() => {}); // Catch error if user hasn't interacted yet
    }
  };

  const nextPage = () => {
    if (currentIndex < totalViews - 1) {
      setDirection(1);
      playSound();
      setCurrentIndex(curr => curr + 1);
    }
  };

  const prevPage = () => {
    if (currentIndex > 0) {
      setDirection(-1);
      playSound();
      setCurrentIndex(curr => curr - 1);
    }
  };

  const currentPages = BOOK_PAGES.slice(
      currentIndex * itemsPerPage, 
      (currentIndex * itemsPerPage) + itemsPerPage
  );

  // 3D Flip Variants
  const variants = {
    enter: (direction: number) => ({
      rotateY: direction > 0 ? 90 : -90,
      opacity: 0,
      scale: 0.9,
      z: -100, // Start slightly "behind"
    }),
    center: {
      zIndex: 1,
      rotateY: 0,
      opacity: 1,
      scale: 1,
      z: 0,
      transition: {
        duration: 0.8,
        ease: [0.16, 1, 0.3, 1], // Custom easy ease for paper weight
      },
    },
    exit: (direction: number) => ({
      zIndex: 0,
      rotateY: direction > 0 ? -90 : 90,
      opacity: 0,
      scale: 0.9,
      z: -100,
      transition: {
        duration: 0.6,
        ease: "easeInOut",
      },
    }),
  };

  return (
    <section className="min-h-screen w-full bg-[#fdfbf7] flex flex-col items-center justify-center py-20 px-4 overflow-hidden">
      <div className="text-center mb-10">
        <h2 className="text-3xl font-serif text-amber-900 mb-2">Livro do Amor</h2>
