                                        src={page.content.value} 
                                        alt="Movie Scene" 
                                        className="w-full h-full object-cover" 
                                    />
                                    {/* Corner Tape Effect */}
                                    <div className="absolute -top-3 left-1/2 -translate-x-1/2 w-24 h-6 bg-amber-100/50 rotate-2 backdrop-blur-sm shadow-sm" />
                                </motion.div>
                            ) : (
                                <div className="relative z-10 w-full h-full flex flex-col justify-center items-center text-center">
                                    {/* Decorative Icon */}
                                    <Sparkles className="w-6 h-6 text-amber-500 mb-6 opacity-50" />

                                    {/* Movie Title */}
                                    {movieTitle && (
                                        <h3 className="font-sans text-amber-900/40 text-xs font-bold uppercase tracking-[0.2em] mb-8 border-b border-amber-900/10 pb-2">
                                            {movieTitle}
                                        </h3>
                                    )}

                                    {/* The Quote */}
                                    <p className="font-serif text-2xl md:text-3xl text-amber-950 leading-relaxed italic">
                                        {movieQuote}
                                    </p>

                                    {/* Decorative End */}
                                    <div className="mt-8 text-amber-900/20 text-xl">~</div>
                                </div>
                            )}

                            {/* Subtle Page Number */}
                            <div className="absolute bottom-4 text-[10px] text-amber-900/20 font-serif">
                                {page.id}
                            </div>
                        </div>
                    )})}

                    {/* If only 1 item on desktop (odd number ending), fill empty space */}
                    {isDesktop && currentPages.length === 1 && (
                         <div className="flex-1 h-full bg-[#fffefc] relative">
                             <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cream-paper.png')] opacity-60 pointer-events-none mix-blend-multiply" />
                             <div className="absolute inset-y-0 left-0 w-8 bg-gradient-to-r from-black/5 to-transparent pointer-events-none" />
                         </div>
                    )}

                </motion.div>
            </AnimatePresence>

        </div>

        {/* Navigation Controls */}
        <button 
            onClick={prevPage}
            disabled={currentIndex === 0}
            className={`absolute z-30 left-2 md:-left-16 p-4 rounded-full bg-amber-50 shadow-xl text-amber-900 transition-all border border-amber-900/10 ${currentIndex === 0 ? 'opacity-30 cursor-not-allowed' : 'hover:scale-110 opacity-100 hover:bg-white'}`}
        >
            <ArrowLeft size={24} />
        </button>

        <button 
            onClick={nextPage}
            disabled={currentIndex === totalViews - 1}
            className={`absolute z-30 right-2 md:-right-16 p-4 rounded-full bg-amber-50 shadow-xl text-amber-900 transition-all border border-amber-900/10 ${currentIndex === totalViews - 1 ? 'opacity-30 cursor-not-allowed' : 'hover:scale-110 opacity-100 hover:bg-white'}`}
        >
            <ArrowRight size={24} />
        </button>
      </div>

    </section>
  );
};

