import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { BOOK_PAGES, PAGE_FLIP_AUDIO } from '../constants';
import { ArrowLeft, ArrowRight, Sparkles } from 'lucide-react';

const SectionBook: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [direction, setDirection] = useState(0); // -1 for left, 1 for right
  const [isDesktop, setIsDesktop] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Handle Resize safely to avoid lag
  useEffect(() => {
    const handleResize = () => setIsDesktop(window.innerWidth >= 768);
    handleResize(); // Initial check
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const itemsPerPage = isDesktop ? 2 : 1;
  const totalViews = Math.ceil(BOOK_PAGES.length / itemsPerPage);

  // Initialize audio
  useEffect(() => {
    audioRef.current = new Audio(PAGE_FLIP_AUDIO);
    audioRef.current.volume = 0.4; // Subtle volume
  }, []);

  const playSound = () => {
    if (audioRef.current) {
      audioRef.current.currentTime = 0;
      audioRef.current.play().catch(() => {});
    }
  };

  const nextPage = () => {
    if (currentIndex < totalViews - 1) {
      setDirection(1);
      playSound();
      setCurrentIndex(curr => curr + 1);
    }
  };

  const prevPage = () => {
    if (currentIndex > 0) {
      setDirection(-1);
      playSound();
      setCurrentIndex(curr => curr - 1);
    }
  };

  const currentPages = BOOK_PAGES.slice(
      currentIndex * itemsPerPage, 
      (currentIndex * itemsPerPage) + itemsPerPage
  );

  // Optimized 3D Flip Variants (Simpler ease for better performance)
  const variants = {
    enter: (direction: number) => ({
      rotateY: direction > 0 ? 90 : -90,
      opacity: 0,
      scale: 0.95, // Reduced scaling for less layout thrashing
      z: -50,
    }),
    center: {
      zIndex: 1,
      rotateY: 0,
      opacity: 1,
      scale: 1,
      z: 0,
      transition: {
        duration: 0.6,
        ease: "circOut", // Faster feel
      },
    },
    exit: (direction: number) => ({
      zIndex: 0,
      rotateY: direction > 0 ? -90 : 90,
      opacity: 0,
      scale: 0.95,
      z: -50,
      transition: {
        duration: 0.4,
        ease: "easeIn",
      },
    }),
  };

  return (
    <section className="min-h-screen w-full bg-[#fdfbf7] flex flex-col items-center justify-center py-20 px-4 overflow-hidden transform-gpu">
